class ErrorBoundary {
  constructor(options = {}) {
    this.fallback = options.fallback;
    this.onError = options.onError;
    this.maxRetries = options.maxRetries ?? 3;
    this.retryCount = 0;
    this.isError = false;
  }

  async run(fn, context) {
    try {
      return await fn.call(context);
    } catch (error) {
      this.isError = true;
      if (this.onError) this.onError(error);

      if (this.retryCount < this.maxRetries) {
        this.retryCount++;
        const delay = Math.min(1000 * Math.pow(2, this.retryCount), 10000);
        await new Promise(resolve => setTimeout(resolve, delay));
        return this.run(fn, context);
      }

      return this._renderFallback(error);
    }
  }

  _renderFallback(error) {
    if (typeof this.fallback === 'function') {
      return this.fallback(error);
    }
    if (this.fallback) return this.fallback;
    return { status: 'error', message: error.message, code: error.code };
  }

  reset() {
    this.isError = false;
    this.retryCount = 0;
  }
}

// Usage with component rendering
async function renderWithBoundary(component, props) {
  const boundary = new ErrorBoundary({
    fallback: (error) => ({
      type: 'Alert',
      variant: 'error',
      message: `Failed to load ${component.name}: ${error.message}`
    })
  });

  return boundary.run(() => component(props));
}

module.exports = { ErrorBoundary, renderWithBoundary };

class ConnectionPool {
  constructor(factory, options = {}) {
    this.factory = factory;
    this.minSize = options.minSize ?? 2;
    this.maxSize = options.maxSize ?? 20;
    this.idleTimeout = options.idleTimeout ?? 30000;
    this.connections = [];
    this.waitingQueue = [];
    this.activeCount = 0;

    for (let i = 0; i < this.minSize; i++) {
      this._createConnection().then(conn => {
        conn.inUse = false;
        this.connections.push(conn);
      });
    }
  }

  async acquire() {
    const idleConn = this.connections.find(c => !c.inUse);
    if (idleConn) {
      idleConn.inUse = true;
      idleConn.lastUsed = Date.now();
      return idleConn;
    }

    if (this.connections.length < this.maxSize) {
      const conn = await this._createConnection();
      conn.inUse = true;
      this.connections.push(conn);
      return conn;
    }

    return new Promise((resolve, reject) => {
      this.waitingQueue.push({ resolve, reject, timeout: setTimeout(() => reject(new Error('Pool timeout')), 5000) });
    });
  }

  release(connection) {
    connection.inUse = false;
    connection.lastUsed = Date.now();
    const waiter = this.waitingQueue.shift();
    if (waiter) {
      clearTimeout(waiter.timeout);
      connection.inUse = true;
      waiter.resolve(connection);
    }
  }

  _createConnection() {
    return this.factory({ maxRetries: 3, timeout: 5000 });
  }

  destroy() {
    this.connections.forEach(conn => conn.close?.());
    this.connections = [];
    this.waitingQueue.forEach(w => w.reject(new Error('Pool destroyed')));
    this.waitingQueue = [];
  }
}

module.exports = ConnectionPool;

class TokenBucketLimiter {
  constructor(options = {}) {
    this.tokensPerSecond = options.rate ?? 10;
    this.maxTokens = options.burst ?? 20;
    this.buckets = new Map();
  }

  allow(clientId) {
    const now = Date.now();
    const bucket = this.buckets.get(clientId) || {
      tokens: this.maxTokens,
      lastRefill: now
    };

    // Refill tokens based on elapsed time
    const elapsed = (now - bucket.lastRefill) / 1000;
    bucket.tokens = Math.min(
      this.maxTokens,
      bucket.tokens + elapsed * this.tokensPerSecond
    );
    bucket.lastRefill = now;

    if (bucket.tokens >= 1) {
      bucket.tokens -= 1;
      this.buckets.set(clientId, bucket);
      return { allowed: true, remaining: Math.floor(bucket.tokens), resetAt: now + (this.maxTokens - bucket.tokens) / this.tokensPerSecond * 1000 };
    }

    this.buckets.set(clientId, bucket);
    return { allowed: false, remaining: 0, retryAfter: (1 - bucket.tokens) / this.tokensPerSecond };
  }

  getRemaining(clientId) {
    const bucket = this.buckets.get(clientId);
    return bucket ? Math.floor(bucket.tokens) : this.maxTokens;
  }

  reset(clientId) {
    this.buckets.delete(clientId);
  }
}

module.exports = TokenBucketLimiter;

class HealthChecker {
  constructor() {
    this.checks = new Map();
    this.status = 'starting';
    this.lastChecked = null;
  }

  register(name, checkFn, timeout = 5000) {
    this.checks.set(name, { fn: checkFn, timeout });
    return this;
  }

  async checkAll() {
    const results = [];
    let hasCriticalFailure = false;

    for (const [name, { fn, timeout }] of this.checks) {
      try {
        const result = await Promise.race([
          fn(),
          new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), timeout))
        ]);
        results.push({ name, status: result?.status ?? 'healthy', healthy: true });
      } catch (error) {
        hasCriticalFailure = true;
        results.push({ name, status: 'unhealthy', healthy: false, error: error.message });
      }
    }

    this.status = hasCriticalFailure ? 'degraded' : 'healthy';
    this.lastChecked = new Date().toISOString();
    return { status: this.status, checks: results, timestamp: this.lastChecked };
  }

  handleRequest(req, res) {
    if (req.url === '/health') {
      return this.checkAll().then(result => {
        res.statusCode = result.status === 'healthy' ? 200 : 503;
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify(result));
      });
    }
    if (req.url === '/ready') {
      res.statusCode = this.status === 'healthy' ? 200 : 503;
      res.end(this.status);
    }
  }
}

module.exports = HealthChecker;

class ConfigLoader {
  constructor(defaults = {}) {
    this.defaults = defaults;
    this.layers = [];
  }

  addLayer(name, source, priority = 0) {
    this.layers.push({ name, source, priority, loaded: false });
    this.layers.sort((a, b) => b.priority - a.priority);
    return this;
  }

  async load() {
    const merged = { ...this.defaults };

    for (const layer of this.layers) {
      try {
        const config = await this._loadSource(layer.source);
        Object.assign(merged, this._deepMerge(merged, config));
        layer.loaded = true;
      } catch (err) {
        console.warn(`Config layer "${layer.name}" failed to load:`, err.message);
      }
    }

    return this._validate(merged);
  }

  _loadSource(source) {
    if (typeof source === 'function') return source();
    if (source instanceof Promise) return source;
    if (typeof source === 'string') return JSON.parse(require('fs').readFileSync(source, 'utf8'));
    return { ...source };
  }

  _deepMerge(target, source) {
    const result = { ...target };
    for (const key of Object.keys(source)) {
      if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
        result[key] = this._deepMerge(result[key] ?? {}, source[key]);
      } else {
        result[key] = source[key];
      }
    }
    return result;
  }

  _validate(config) {
    const required = this.defaults.__required ?? [];
    for (const key of required) {
      if (!(key in config) || config[key] === undefined) {
        throw new Error(`Missing required config key: ${key}`);
      }
    }
    return config;
  }
}

module.exports = ConfigLoader;

class StructuredLogger {
  constructor(options = {}) {
    this.serviceName = options.serviceName ?? 'app';
    this.level = options.level ?? 'info';
    this.outputStream = options.stream ?? process.stdout;
    this.context = options.context ?? {};
    this.levels = { debug: 10, info: 20, warn: 30, error: 40 };
  }

  child(extraContext) {
    return new StructuredLogger({
      serviceName: this.serviceName,
      level: this.level,
      stream: this.outputStream,
      context: { ...this.context, ...extraContext }
    });
  }

  log(level, message, meta = {}) {
    if (this.levels[level] < this.levels[this.level]) return;

    const entry = {
      timestamp: new Date().toISOString(),
      level,
      service: this.serviceName,
      ...this.context,
      ...meta,
      msg: message
    };

    this.outputStream.write(JSON.stringify(entry) + '\n');
  }

  debug(msg, meta) { this.log('debug', msg, meta); }
  info(msg, meta) { this.log('info', msg, meta); }
  warn(msg, meta) { this.log('warn', msg, meta); }
  error(msg, meta) { this.log('error', msg, meta); }

  requestLog(req) {
    const start = Date.now();
    return {
      before: () => this.info('request.start', { method: req.method, url: req.url }),
      after: (res) => this.info('request.complete', {
        method: req.method,
        url: req.url,
        status: res.statusCode,
        durationMs: Date.now() - start
      })
    };
  }
}

module.exports = StructuredLogger;

async function retryWithBackoff(fn, options = {}) {
  const maxAttempts = options.attempts ?? 3;
  const baseDelay = options.baseDelay ?? 1000;
  const maxDelay = options.maxDelay ?? 30000;
  const factor = options.factor ?? 2;
  const jitter = options.jitter ?? true;
  const retryOn = options.retryOn ?? (() => true);

  let lastError;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const result = await fn({ attempt });
      return { success: true, result, attempts: attempt };
    } catch (error) {
      lastError = error;

      if (attempt === maxAttempts) break;
      if (!retryOn(error, attempt)) break;

      const exponentialDelay = baseDelay * Math.pow(factor, attempt - 1);
      const jitterValue = jitter ? Math.random() * exponentialDelay * 0.2 : 0;
      const delay = Math.min(exponentialDelay + jitterValue, maxDelay);

      console.log(`Attempt ${attempt} failed, retrying in ${Math.round(delay)}ms...`);
      await sleep(delay);
    }
  }

  return {
    success: false,
    error: lastError,
    attempts: maxAttempts,
    lastError
  };
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

module.exports = { retryWithBackoff, sleep };

class FeatureFlagManager {
  constructor() {
    this.flags = new Map();
    this.listeners = new Map();
  }

  register(flagName, config = {}) {
    this.flags.set(flagName, {
      enabled: config.enabled ?? false,
      rollout: config.rollout ?? 0,
      conditions: config.conditions ?? [],
      metadata: config.metadata ?? {}
    });
  }

  isEnabled(flagName, context = {}) {
    const flag = this.flags.get(flagName);
    if (!flag) return false;

    if (!flag.enabled) return false;

    // Percentage rollout
    if (flag.rollout > 0 && flag.rollout < 100) {
      const hash = this._hash(context.userId ?? '');
      if (hash % 100 >= flag.rollout) return false;
    }

    // Custom conditions
    for (const condition of flag.conditions) {
      if (!condition.evaluate(context)) return false;
    }

    return true;
  }

  setEnabled(flagName, enabled) {
    const flag = this.flags.get(flagName);
    if (flag) {
      flag.enabled = enabled;
      this._notify(flagName);
    }
  }

  _hash(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0;
    }
    return Math.abs(hash);
  }

  _notify(flagName) {
    this.listeners.get(flagName)?.forEach(cb => cb(this.flags.get(flagName)));
  }

  onChange(flagName, callback) {
    if (!this.listeners.has(flagName)) this.listeners.set(flagName, new Set());
    this.listeners.get(flagName).add(callback);
    return () => this.listeners.get(flagName)?.delete(callback);
  }
}

module.exports = FeatureFlagManager;
